package net.minecraft.network.play.server;

import net.minecraft.network.Packet;
import net.minecraft.network.PacketBuffer;
import net.minecraft.network.play.INetHandlerPlayClient;
import net.minecraft.world.chunk.Chunk;
import java.io.IOException;

public class S21PacketChunkData implements Packet<INetHandlerPlayClient> {
    private int chunkX;
    private int chunkZ;
    private boolean groundUpContinuous;
    private int bitmask;
    private byte[] data;
    private int dataLength;

    public S21PacketChunkData() {}
    public S21PacketChunkData(Chunk chunkIn, boolean p_i45196_2_, int p_i45196_3_) {
        this.chunkX = chunkIn.xPosition;
        this.chunkZ = chunkIn.zPosition;
        this.groundUpContinuous = p_i45196_2_;
        ExtendedBlockStorage[] storage = chunkIn.getBlockStorageArray();
        this.bitmask = chunkIn.getPackedSectionData(p_i45196_2_);
        this.data = chunkIn.getDataForProccessing(p_i45196_2_, p_i45196_3_);
        this.dataLength = this.data.length;
    }

    public void processPacket(INetHandlerPlayClient handler) { handler.handleChunkData(this); }
    public int getChunkX() { return this.chunkX; }
    public int getChunkZ() { return this.chunkZ; }
    public boolean isGroundUpContinuous() { return this.groundUpContinuous; }
    public int getBitmask() { return this.bitmask; }
    public byte[] getData() { return this.data; }
    public int getDataLength() { return this.dataLength; }
}

